sys_ws_operation.operation_script:
(function process( /*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
    var processInput;
    var reqBody = request.body.data;
    var sync = new mydesign_util();
    gs.info(' SCRIPTED REST API POST' + JSON.stringify(reqBody));
    // implement resource here
    if (reqBody.nature.toLowerCase() == 'service request') {
        processInput = sync.transformRequest(reqBody);
        //var res = {"Status":"200"};
        //response.setStatus('200');
        response.setBody(processInput);
    } else if (reqBody.nature.toLowerCase() == 'service incident') {
        //	if(sync.checkValidPostCall(reqBody)){
        processInput = sync.transform(reqBody);
        response.setStatus(processInput['status_code']);
        response.setBody(processInput);
    } else {
        // return response for invalid/ignored Incident calls
        var returnBody = {};
        returnBody['status'] = 'ignored';
        returnBody['status_code'] = 200;
        returnBody['status_message'] = 'Ticket details matching the record in exclusion list and hence the ' + reqBody.nature + ' creation is ignored.';
        response.setBody(returnBody);
    }

})(request, response);
